INSERT INTO TBL_CIRCULAR_OPTION (
	CIRCULAROPTIONID,	MEMBERID,	ISMAILRECEIVE,	LISTCNT,	ISPREVIEW,	PREVIEWLISTVALUE,	PREVIEWCONTENTVALUE,	TENANTID	
)
VALUES (
	#circularOptionId#, #memberId#, #isMailReceive#, #listCnt#, #isPreview#, #previewListValue#, #previewContentValue#, #tenantId#
)


INSERT INTO TBL_CIRCULAR_FILE(
    CIRCULARFILEID ,CIRCULARID, FILENAME, FILESIZE, FILEPATH, TENANTID
) VALUES (
    #circularFileID#, #circularID#, #fileName#, #fileSize#, #filePath#, #tenantID#
)


INSERT INTO TBL_CIRCULAR_BM (
	TITLE,		MEMBERID,		REGDATE,		TENANTID
)
VALUES (
	#title#, #memberId#, #regDate#, #tenantId#
)
